+import {Options, RuleType} from '../rules';
+import {IgnoreTypes} from '../utils/ignore-types';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type MarkdownLink = {
+  end: number,
+  image: boolean,
+  label: string,
+  target: string,
+};
+
+/** Convert the small, unambiguous subset of Obsidian and Markdown link syntax. */
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [
+        IgnoreTypes.yaml,
+        IgnoreTypes.code,
+        IgnoreTypes.inlineCode,
+        IgnoreTypes.math,
+        IgnoreTypes.inlineMath,
+        IgnoreTypes.html,
+        IgnoreTypes.templaterCommand,
+        IgnoreTypes.obsidianMultiLineComments,
+        IgnoreTypes.table,
+      ],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown') {
+      text = wikiToMarkdown(text, false);
+    } else if (options.linkStyle === 'wiki') {
+      text = markdownToWiki(text, false);
+    }
+
+    if (options.imageStyle === 'markdown') {
+      text = wikiToMarkdown(text, true);
+    } else if (options.imageStyle === 'wiki') {
+      text = markdownToWiki(text, true);
+    }
+
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to Markdown',
+        before: '[[Page#Heading]]\
![[image.png|300x200]]',
+        after: '[Page > Heading](Page#Heading)\
![image.png](image.png)',
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert inline Markdown links and images to wiki syntax',
+        before: '[Page > Heading](Page#Heading)\
![alt text](image.png)',
+        after: '[[Page#Heading]]\
![[image.png|alt text]]',
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    const records = [
+      {value: 'no-change' as const, description: 'Leave this syntax unchanged.'},
+      {value: 'markdown' as const, description: 'Convert wiki syntax to Markdown.'},
+      {value: 'wiki' as const, description: 'Convert Markdown syntax to wiki syntax.'},
+    ];
+    return [
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.link-style.name',
+        descriptionKey: 'rules.link-style.link-style.description',
+        optionsKey: 'linkStyle',
+        records,
+      }),
+      new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+        OptionsClass: LinkStyleOptions,
+        nameKey: 'rules.link-style.image-style.name',
+        descriptionKey: 'rules.link-style.image-style.description',
+        optionsKey: 'imageStyle',
+        records,
+      }),
+    ];
+  }
+}
+
+function wikiToMarkdown(text: string, images: boolean): string {
+  const pattern = /(!?)\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]+))?\\]\\]/g;
+  return text.replace(pattern, (match, bang: string, target: string, display: string) => {
+    if ((bang === '!') !== images) {
+      return match;
+    }
+
+    if (images) {
+      const alt = display == null || isEmbedSize(display) ? target : display;
+      return `![${alt}](${target})`;
+    }
+
+    return `[${display ?? defaultHeadingDisplay(target)}](${target})`;
+  });
+}
+
+function markdownToWiki(text: string, images: boolean): string {
+  let output = '';
+  let position = 0;
+  while (position < text.length) {
+    if (text[position] !== '[' || isEscaped(text, position)) {
+      output += text[position++];
+      continue;
+    }
+
+    const link = parseMarkdownLink(text, position);
+    if (!link || link.image !== images || link.target.includes('://') || !canRepresentInWiki(link.target) || !canRepresentInWiki(link.label)) {
+      output += text[position++];
+      continue;
+    }
+
+    const display = unescapeMarkdown(link.label);
+    const target = unescapeMarkdown(link.target);
+    if (target.includes('://') || !canRepresentInWiki(target) || !canRepresentInWiki(display)) {
+      output += text[position++];
+      continue;
+    }
+
+    if (images) {
+      output += `![[${target}${display === '' || display === target ? '' : `|${display}`}]]`;
+    } else {
+      output += `[[${target}${display === target || display === defaultHeadingDisplay(target) ? '' : `|${display}`}]]`;
+    }
+    position = link.end;
+  }
+  return output;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const image = start > 0 && text[start - 1] === '!' && !isEscaped(text, start - 1);
+  const contentStart = start + 1;
+  let depth = 1;
+  let cursor = contentStart;
+  for (; cursor < text.length; cursor++) {
+    if (text[cursor] === '\
' || text[cursor] === '\\r') return null;
+    if (isEscaped(text, cursor)) continue;
+    if (text[cursor] === '[') depth++;
+    if (text[cursor] === ']' && --depth === 0) break;
+  }
+  if (depth !== 0 || text[cursor + 1] !== '(') return null;
+
+  const destinationStart = cursor + 2;
+  depth = 1;
+  cursor = destinationStart;
+  for (; cursor < text.length; cursor++) {
+    if (text[cursor] === '\
' || text[cursor] === '\\r') return null;
+    if (isEscaped(text, cursor)) continue;
+    if (text[cursor] === '(') depth++;
+    if (text[cursor] === ')' && --depth === 0) break;
+  }
+  if (depth !== 0) return null;
+
+  const target = parseDestination(text.slice(destinationStart, cursor));
+  if (target == null) return null;
+  return {end: cursor + 1, image, label: text.slice(contentStart, cursor - (cursor - contentStart)), target};
+}
+
+function parseDestination(value: string): string | null {
+  const trimmed = value.trim();
+  if (trimmed.startsWith('<')) {
+    const close = findUnescaped(trimmed, '>', 1);
+    if (close === -1 || close !== trimmed.length - 1) return null;
+    return trimmed.slice(1, -1);
+  }
+
+  // Whitespace in an unbracketed destination either makes it invalid or starts a title.
+  for (let index = 0; index < value.length; index++) {
+    if (/\\s/.test(value[index]) && !isEscaped(value, index)) return null;
+  }
+  return value;
+}
+
+function findUnescaped(value: string, character: string, start: number): number {
+  for (let index = start; index < value.length; index++) {
+    if (value[index] === character && !isEscaped(value, index)) return index;
+  }
+  return -1;
+}
+
+function isEscaped(value: string, index: number): boolean {
+  let slashCount = 0;
+  for (let cursor = index - 1; cursor >= 0 && value[cursor] === '\\\'; cursor--) slashCount++;
+  return slashCount % 2 === 1;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const hash = target.indexOf('#');
+  if (hash === -1) return target;
+  const page = target.slice(0, hash);
+  const heading = target.slice(hash + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
+
+function isEmbedSize(display: string): boolean {
+  return /^\\d+(?:x\\d+)?$/.test(display);
+}
+
+function canRepresentInWiki(value: string): boolean {
+  return !value.includes('\
') && !value.includes('\\r') && !value.includes('|') && !value.includes(']]');
+}
